#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/wait.h>

int main() {
  int i;
  for (i = 0; i < 200; i++) {
    if (fork() == 0) {
      sleep(5);
      exit(0);
    }
  }

  for (i = 0; i < 200; i++) {
    wait(NULL);
  }

  printf("All 200 processes completed\n");
  return 0;
}
